 1→import { createRemoteJWKSet, jwtVerify } from "jose";
 2→
 3→export type BrainTokenClaims = {
 4→  sub: string;
 5→  scope?: string;
 6→  aud?: string;
 7→  iss?: string;
 8→  exp?: number;
 9→  iat?: number;
10→  "urn:brain:workspace"?: string;
11→  "urn:brain:workspace_name"?: string;
12→  "urn:brain:agent_type"?: string;
13→  [key: string]: unknown;
14→};
15→
16→/**
17→ * Create a JWT validator that verifies access tokens using the auth server's JWKS.
18→ * Tokens must be JWTs (issued when `resource` param is passed during authorization).
19→ *
20→ * Uses jose's createRemoteJWKSet directly instead of better-auth's verifyAccessToken
21→ * because the latter uses a module-level JWKS singleton cache that breaks when
22→ * multiple test servers (each with their own JWKS keys) run concurrently.
23→ */
24→export function createJwtValidator(issuerUrl: string) {
25→  // issuerUrl is the server baseURL (e.g. "http://localhost:3000").
26→  // Better Auth mounts at /api/auth (basePath), so JWKS and issuer include that path.
27→  const authBase = issuerUrl.endsWith("/api/auth") ? issuerUrl : `${issuerUrl}/api/auth`;
28→  const jwksUrl = new URL(`${authBase}/jwks`);
29→  const issuer = authBase;
30→
31→  // createRemoteJWKSet maintains its own per-URL cache with proper key rotation
32→  const getKey = createRemoteJWKSet(jwksUrl);
33→
34→  return async (token: string): Promise<BrainTokenClaims> => {
35→    const { payload } = await jwtVerify(token, getKey, {
36→      issuer,
37→      audience: issuerUrl,
38→    });
39→    return payload as BrainTokenClaims;
40→  };
41→}
