 1→import type { RecordId } from "surrealdb";
 2→
 3→// --- Intent Status (state machine states) ---
 4→
 5→export type IntentStatus =
 6→  | "draft"
 7→  | "pending_auth"
 8→  | "pending_veto"
 9→  | "authorized"
10→  | "executing"
11→  | "completed"
12→  | "vetoed"
13→  | "failed";
14→
15→// --- Action Specification ---
16→
17→export type ActionSpec = {
18→  provider: string;
19→  action: string;
20→  params?: Record<string, unknown>;
21→};
22→
23→// --- Budget Limit ---
24→
25→export type BudgetLimit = {
26→  amount: number;
27→  currency: string;
28→};
29→
30→// --- Evaluation Result ---
31→
32→export type EvaluationResult = {
33→  decision: "APPROVE" | "REJECT";
34→  risk_score: number;
35→  reason: string;
36→};
37→
38→// --- Routing Decision (discriminated union) ---
39→
40→export type RoutingDecision =
41→  | { route: "auto_approve" }
42→  | { route: "veto_window"; expires_at: Date }
43→  | { route: "reject"; reason: string };
44→
45→// --- Intent Record ---
46→
47→export type IntentRecord = {
48→  id: RecordId<"intent", string>;
49→  goal: string;
50→  reasoning: string;
51→  status: IntentStatus;
52→  priority: number;
53→  action_spec: ActionSpec;
54→  budget_limit?: BudgetLimit;
55→  evaluation?: EvaluationResult & {
56→    evaluated_at: Date;
57→    policy_only: boolean;
58→  };
59→  veto_expires_at?: Date;
60→  veto_reason?: string;
61→  error_reason?: string;
62→  trace_id: string;
63→  requester: RecordId<"identity", string>;
64→  workspace: RecordId<"workspace", string>;
65→  created_at: Date;
66→  updated_at?: Date;
67→  expiry?: Date;
68→};
