 1→import { RecordId, type Surreal } from "surrealdb";
 2→
 3→export async function resolveIdentity(input: {
 4→  surreal: Surreal;
 5→  provider: string;
 6→  providerId: string;
 7→  workspaceRecord: RecordId<"workspace", string>;
 8→}): Promise<RecordId<"identity", string> | undefined> {
 9→  const [rows] = await input.surreal.query<[Array<{ id: RecordId<"identity", string> }>]>(
10→    `SELECT id FROM identity
11→     WHERE id IN (SELECT VALUE \`in\` FROM member_of WHERE out = $workspace)
12→       AND identities[WHERE provider = $provider AND id = $providerId]
13→     LIMIT 1;`,
14→    {
15→      workspace: input.workspaceRecord,
16→      provider: input.provider,
17→      providerId: input.providerId,
18→    },
19→  );
20→
21→  return rows.length > 0 ? rows[0].id : undefined;
22→}
23→
24→/**
25→ * Resolve identity by email: find person by email, then traverse spoke edge to identity,
26→ * scoped to workspace via member_of.
27→ */
28→export async function resolveByEmail(input: {
29→  surreal: Surreal;
30→  email: string;
31→  workspaceRecord: RecordId<"workspace", string>;
32→}): Promise<RecordId<"identity", string> | undefined> {
33→  const normalizedEmail = input.email.trim().toLowerCase();
34→  if (normalizedEmail.length === 0) return undefined;
35→
36→  // Find person by email, then traverse identity_person spoke to get identity in this workspace
37→  const [rows] = await input.surreal.query<[Array<{ id: RecordId<"identity", string> }>]>(
38→    `SELECT id FROM identity
39→     WHERE id IN (
40→       SELECT VALUE in FROM identity_person
41→       WHERE out IN (SELECT VALUE id FROM person WHERE string::lowercase(contact_email) = $email)
42→     )
43→       AND id IN (SELECT VALUE in FROM member_of WHERE out = $workspace)
44→     LIMIT 1;`,
45→    {
46→      workspace: input.workspaceRecord,
47→      email: normalizedEmail,
48→    },
49→  );
50→
51→  return rows.length > 0 ? rows[0].id : undefined;
52→}
