 1→import type { EvaluationResult, RoutingDecision } from "./types";
 2→
 3→const DEFAULT_AUTO_APPROVE_THRESHOLD = 30;
 4→const DEFAULT_VETO_WINDOW_MINUTES = 30;
 5→
 6→type RiskRouterOptions = {
 7→  threshold?: number;
 8→  vetoWindowMinutes?: number;
 9→};
10→
11→export function routeByRisk(
12→  evaluation: EvaluationResult,
13→  options?: RiskRouterOptions,
14→): RoutingDecision {
15→  if (evaluation.decision === "REJECT") {
16→    return { route: "reject", reason: evaluation.reason };
17→  }
18→
19→  const threshold = options?.threshold ?? DEFAULT_AUTO_APPROVE_THRESHOLD;
20→
21→  if (evaluation.risk_score <= threshold) {
22→    return { route: "auto_approve" };
23→  }
24→
25→  const vetoMinutes = options?.vetoWindowMinutes ?? DEFAULT_VETO_WINDOW_MINUTES;
26→  const expiresAt = new Date(Date.now() + vetoMinutes * 60 * 1000);
27→
28→  return { route: "veto_window", expires_at: expiresAt };
29→}
