  1→import { jsonError, jsonResponse } from "../http/response";
  2→import { logError, logInfo } from "../http/observability";
  3→import { updateIntentStatus, listPendingIntents } from "./intent-queries";
  4→import { evaluateIntent, createLlmEvaluator } from "./authorizer";
  5→import { routeByRisk } from "./risk-router";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import type { IntentRecord } from "./types";
  8→
  9→// --- Route Handler Types ---
 10→
 11→type IntentRouteHandlers = {
 12→  handleEvaluate: (intentId: string, request: Request) => Promise<Response>;
 13→  handleVeto: (workspaceId: string, intentId: string, request: Request) => Promise<Response>;
 14→  handleListPending: (workspaceId: string) => Promise<Response>;
 15→};
 16→
 17→// --- Factory ---
 18→
 19→export function createIntentRouteHandlers(deps: ServerDependencies): IntentRouteHandlers {
 20→  const { surreal } = deps;
 21→
 22→  const llmEvaluator = createLlmEvaluator(deps.extractionModel);
 23→
 24→  const handleEvaluate = async (intentId: string, request: Request): Promise<Response> => {
 25→    // Called by SurrealQL EVENT via http::post - receives full intent record as body
 26→    let body: IntentRecord | undefined;
 27→    try {
 28→      body = await request.json() as IntentRecord;
 29→    } catch {
 30→      body = undefined;
 31→    }
 32→
 33→    const bodyIntentId = body && typeof body.id === "object" && body.id !== undefined
 34→      ? (body.id.id as string)
 35→      : undefined;
 36→
 37→    if (bodyIntentId && bodyIntentId !== intentId) {
 38→      return jsonError("Intent ID mismatch between path and payload", 400);
 39→    }
 40→
 41→    if (!body) {
 42→      return jsonError("Invalid JSON body", 400);
 43→    }
 44→
 45→    if (!body.requester) {
 46→      return jsonError("Missing requester in intent body", 400);
 47→    }
 48→
 49→    logInfo("intent.evaluate.received", "Evaluate endpoint received intent", {
 50→      intentId,
 51→      status: body.status,
 52→      goal: body.goal,
 53→    });
 54→
 55→    // Idempotency guard: only process intents in pending_auth status
 56→    if (body.status !== "pending_auth") {
 57→      logInfo("intent.evaluate.skipped", "Intent not in pending_auth status", {
 58→        intentId,
 59→        currentStatus: body.status,
 60→      });
 61→      return jsonError(`Intent is in '${body.status}' status, expected 'pending_auth'`, 409);
 62→    }
 63→
 64→    try {
 65→      // Pipeline: policy gate -> LLM evaluator -> risk router -> status update
 66→      const requesterId = typeof body.requester === "object" && body.requester !== undefined
 67→        ? (body.requester.id as string)
 68→        : String(body.requester);
 69→
 70→      const evaluation = await evaluateIntent({
 71→        intent: {
 72→          goal: body.goal,
 73→          reasoning: body.reasoning,
 74→          action_spec: body.action_spec,
 75→          budget_limit: body.budget_limit,
 76→          requester: requesterId,
 77→        },
 78→        policy: {},
 79→        llmEvaluator,
 80→      });
 81→
 82→      const routing = routeByRisk(evaluation);
 83→      const evaluationRecord = {
 84→        ...evaluation,
 85→        evaluated_at: new Date(),
 86→      };
 87→
 88→      switch (routing.route) {
 89→        case "auto_approve": {
 90→          const result = await updateIntentStatus(surreal, intentId, "authorized", {
 91→            evaluation: evaluationRecord,
 92→          });
 93→          if (!result.ok) {
 94→            logError(
 95→              "intent.evaluate.update_failed",
 96→              "Failed to update intent status to authorized",
 97→              new Error(result.error),
 98→              { intentId },
 99→            );
100→            return jsonError(result.error, 409);
101→          }
102→          logInfo("intent.authorized", "Intent auto-approved", { intentId });
103→          return jsonResponse({ intentId, status: "authorized", evaluation }, 200);
104→        }
105→
106→        case "veto_window": {
107→          const result = await updateIntentStatus(surreal, intentId, "pending_veto", {
108→            evaluation: evaluationRecord,
109→            veto_expires_at: routing.expires_at,
110→          });
111→          if (!result.ok) {
112→            logError(
113→              "intent.evaluate.update_failed",
114→              "Failed to update intent status to pending_veto",
115→              new Error(result.error),
116→              { intentId },
117→            );
118→            return jsonError(result.error, 409);
119→          }
120→          logInfo("intent.pending_veto", "Intent requires veto window", {
121→            intentId,
122→            veto_expires_at: routing.expires_at.toISOString(),
123→          });
124→          return jsonResponse({
125→            intentId,
126→            status: "pending_veto",
127→            evaluation,
128→            veto_expires_at: routing.expires_at.toISOString(),
129→          }, 200);
130→        }
131→
132→        case "reject": {
133→          const result = await updateIntentStatus(surreal, intentId, "vetoed", {
134→            evaluation: evaluationRecord,
135→          });
136→          if (!result.ok) {
137→            logError(
138→              "intent.evaluate.update_failed",
139→              "Failed to update intent status to vetoed",
140→              new Error(result.error),
141→              { intentId },
142→            );
143→            return jsonError(result.error, 409);
144→          }
145→          logInfo("intent.vetoed", "Intent rejected by evaluation", {
146→            intentId,
147→            reason: routing.reason,
148→          });
149→          return jsonResponse({ intentId, status: "vetoed", evaluation }, 200);
150→        }
151→      }
152→    } catch (error) {
153→      logError("intent.evaluate.error", "Intent evaluation pipeline failed", error, {
154→        intentId,
155→      });
156→      return jsonError("Internal evaluation error", 500);
157→    }
158→  };
159→
160→  const handleVeto = async (
161→    workspaceId: string,
162→    intentId: string,
163→    request: Request,
164→  ): Promise<Response> => {
165→    let body: { reason: string };
166→    try {
167→      body = await request.json() as { reason: string };
168→    } catch {
169→      return jsonError("Invalid JSON body", 400);
170→    }
171→
172→    if (!body.reason || typeof body.reason !== "string" || body.reason.trim().length === 0) {
173→      return jsonError("reason is required", 400);
174→    }
175→
176→    const result = await updateIntentStatus(surreal, intentId, "vetoed", {
177→      veto_reason: body.reason.trim(),
178→    });
179→
180→    if (!result.ok) {
181→      logError("intent.veto.failed", "Failed to veto intent", new Error(result.error), {
182→        intentId,
183→        workspaceId,
184→      });
185→      return jsonError(result.error, 409);
186→    }
187→
188→    logInfo("intent.vetoed", "Intent vetoed by user", {
189→      intentId,
190→      workspaceId,
191→      reason: body.reason.trim(),
192→    });
193→
194→    return jsonResponse({
195→      intentId,
196→      status: "vetoed",
197→    }, 200);
198→  };
199→
200→  const handleListPending = async (workspaceId: string): Promise<Response> => {
201→    const intents = await listPendingIntents(surreal, workspaceId);
202→
203→    return jsonResponse({
204→      intents: intents.map((intent) => ({
205→        id: intent.id.id as string,
206→        goal: intent.goal,
207→        reasoning: intent.reasoning,
208→        priority: intent.priority,
209→        action_spec: intent.action_spec,
210→        veto_expires_at: intent.veto_expires_at,
211→        created_at: intent.created_at,
212→      })),
213→    }, 200);
214→  };
215→
216→  return { handleEvaluate, handleVeto, handleListPending };
217→}
