  1→import { betterAuth } from "better-auth";
  2→import { jwt } from "better-auth/plugins";
  3→import { oauthProvider } from "@better-auth/oauth-provider";
  4→import { RecordId, type Surreal } from "surrealdb";
  5→import { surrealdbAdapter } from "./adapter";
  6→import { BRAIN_SCOPES } from "./scopes";
  7→
  8→export type AuthConfig = {
  9→  betterAuthSecret: string;
 10→  betterAuthUrl: string;
 11→  githubClientId: string;
 12→  githubClientSecret: string;
 13→};
 14→
 15→export function createAuth(surreal: Surreal, config: AuthConfig) {
 16→  const allScopes = [
 17→    "openid",
 18→    "profile",
 19→    "email",
 20→    "offline_access",
 21→    ...Object.keys(BRAIN_SCOPES),
 22→  ];
 23→
 24→  return betterAuth({
 25→    secret: config.betterAuthSecret,
 26→    baseURL: config.betterAuthUrl,
 27→    basePath: "/api/auth",
 28→    database: surrealdbAdapter(surreal),
 29→    user: {
 30→      modelName: "person",
 31→      fields: {
 32→        email: "contact_email",
 33→        emailVerified: "email_verified",
 34→        createdAt: "created_at",
 35→        updatedAt: "updated_at",
 36→      },
 37→    },
 38→    session: {
 39→      storeSessionInDatabase: true,
 40→      fields: {
 41→        userId: "person_id",
 42→        expiresAt: "expires_at",
 43→        ipAddress: "ip_address",
 44→        userAgent: "user_agent",
 45→        createdAt: "created_at",
 46→        updatedAt: "updated_at",
 47→      },
 48→    },
 49→    account: {
 50→      fields: {
 51→        userId: "person_id",
 52→        accountId: "account_id",
 53→        providerId: "provider_id",
 54→        accessToken: "access_token",
 55→        refreshToken: "refresh_token",
 56→        accessTokenExpiresAt: "access_token_expires_at",
 57→        refreshTokenExpiresAt: "refresh_token_expires_at",
 58→        idToken: "id_token",
 59→        createdAt: "created_at",
 60→        updatedAt: "updated_at",
 61→      },
 62→    },
 63→    verification: {
 64→      fields: {
 65→        expiresAt: "expires_at",
 66→        createdAt: "created_at",
 67→        updatedAt: "updated_at",
 68→      },
 69→    },
 70→    emailAndPassword: {
 71→      enabled: true,
 72→    },
 73→    socialProviders: {
 74→      github: {
 75→        clientId: config.githubClientId,
 76→        clientSecret: config.githubClientSecret,
 77→      },
 78→    },
 79→    plugins: [
 80→      jwt(),
 81→      oauthProvider({
 82→        loginPage: "/sign-in",
 83→        consentPage: "/consent",
 84→        scopes: allScopes,
 85→        validAudiences: [config.betterAuthUrl],
 86→        allowDynamicClientRegistration: true,
 87→        allowUnauthenticatedClientRegistration: true,
 88→        accessTokenExpiresIn: 3600,
 89→        refreshTokenExpiresIn: 2592000,
 90→        customAccessTokenClaims: async ({ user }) => {
 91→          if (!user) return {};
 92→          const [memberRows] = await surreal.query<
 93→            [Array<{ workspace_id: RecordId<"workspace", string>; workspace_name: string }>]
 94→          >(
 95→            `SELECT out.id AS workspace_id, out.name AS workspace_name
 96→             FROM member_of
 97→             WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person)
 98→             LIMIT 1;`,
 99→            { person: new RecordId("person", user.id) },
100→          );
101→
102→          if (memberRows.length === 0) {
103→            return {};
104→          }
105→
106→          return {
107→            "urn:brain:workspace": memberRows[0].workspace_id.id as string,
108→            "urn:brain:workspace_name": memberRows[0].workspace_name,
109→            "urn:brain:agent_type": "code_agent",
110→          };
111→        },
112→      }),
113→    ],
114→  });
115→}
116→
117→export type Auth = ReturnType<typeof createAuth>;
